@startuml
title netnotes

skinparam classAttributeIconSize 0
skinparam shadowing false
skinparam linetype ortho

class User <<C>> {
  String name
  String email
}

class Shelf <<C>> {
  String name
}

class Note <<C>> {
  String title
  String body
}

class Article <<C>> {
  String title
  String url
}

class Tag <<C>> {
  String body
}

' User relations
User --> Note : creates
User --> Shelf : likes
User --> Shelf : creates
User --> Note : likes
User --> Article : finds
User --> Article : likes
User --> Tag : follows
User --> User : follows

' Shelf contains Note and Article (aggregation)
Shelf o--> Note : contains
Shelf o--> Article : contains

' Tag attaches to Note and Article (composition)
Note *--> Tag : attaches
Article *--> Tag : attaches

@enduml
